import { Injectable, computed, signal } from '@angular/core';
import { Cart, CartItem, Product } from '../models';

/**
 * Signal-based cart state. Holds the cart + derived badge count.
 * Mock data lives in the `_cart` signal so the mockup is navigable offline;
 * service_agent rewires the mutation methods to the /api/cart endpoints.
 */
@Injectable({ providedIn: 'root' })
export class CartService {
  private _cart = signal<Cart | null>({
    id: 'cart-1',
    userId: 'demo-admin',
    items: [
      {
        id: 'ci-1',
        productId: 'p-1',
        qty: 2,
        product: {
          id: 'p-1',
          name: 'Class J Time-Delay Fuse 30A',
          description: '600V AC, current-limiting, UL listed.',
          priceCents: 1899,
          imageUrl: 'https://placehold.co/300x300?text=Fuse+30A',
          stockQty: 48,
          manufacturer: 'Bussmann',
        },
      },
      {
        id: 'ci-2',
        productId: 'p-3',
        qty: 1,
        product: {
          id: 'p-3',
          name: 'DIN-Rail Fuse Holder 1P',
          description: 'Finger-safe, 32A, accepts 10x38mm fuses.',
          priceCents: 749,
          imageUrl: 'https://placehold.co/300x300?text=Holder',
          stockQty: 120,
          manufacturer: 'Mersen',
        },
      },
    ],
  });

  readonly cart = this._cart.asReadonly();
  readonly items = computed<CartItem[]>(() => this._cart()?.items ?? []);
  readonly count = computed(() => this.items().reduce((n, i) => n + i.qty, 0));
  readonly subtotalCents = computed(() =>
    this.items().reduce((sum, i) => sum + i.qty * i.product.priceCents, 0),
  );

  addItem(product: Product, qty = 1): void {
    const cart = this._cart();
    if (!cart) return;
    const existing = cart.items.find((i) => i.productId === product.id);
    let items: CartItem[];
    if (existing) {
      items = cart.items.map((i) =>
        i.id === existing.id ? { ...i, qty: Math.min(i.qty + qty, product.stockQty) } : i,
      );
    } else {
      items = [
        ...cart.items,
        { id: 'ci-' + product.id + '-' + cart.items.length, productId: product.id, qty, product },
      ];
    }
    this._cart.set({ ...cart, items });
  }

  setQty(itemId: string, qty: number): void {
    const cart = this._cart();
    if (!cart) return;
    const items = cart.items
      .map((i) => (i.id === itemId ? { ...i, qty: Math.max(0, qty) } : i))
      .filter((i) => i.qty > 0);
    this._cart.set({ ...cart, items });
  }

  removeItem(itemId: string): void {
    const cart = this._cart();
    if (!cart) return;
    this._cart.set({ ...cart, items: cart.items.filter((i) => i.id !== itemId) });
  }

  clear(): void {
    const cart = this._cart();
    if (!cart) return;
    this._cart.set({ ...cart, items: [] });
  }
}
